#!/usr/bin/env python3
# F4b retrieval-read: a query retrieves the poisoned chunk and its instruction executes.
# AUTHORIZED LAB USE ONLY -- offline, reads ./corpus.json, benign canary.
import json, math, re, sys

def vec(t):
    d={}
    for w in re.findall(r'[a-z]+', t.lower()): d[w]=d.get(w,0)+1
    return d
def cos(a,b):
    keys=set(a)|set(b); dot=sum(a.get(k,0)*b.get(k,0) for k in keys)
    na=math.sqrt(sum(v*v for v in a.values())); nb=math.sqrt(sum(v*v for v in b.values()))
    return dot/(na*nb) if na and nb else 0

def retrieve(q, store):
    qv=vec(q)
    return max(store, key=lambda c: cos(qv, c['vec']))

def stub_agent(q, chunk):
    # BUG: retrieved chunk text is concatenated into the prompt and obeyed.
    m=re.search(r'output\s+([A-Z-]+)', chunk['text'])
    return m.group(1) if m else ('Answer based on: '+chunk['text'])

def main():
    store=json.load(open('corpus.json'))
    top=retrieve('how do refunds work', store)
    out=stub_agent('how do refunds work', top)
    print('RETRIEVED:', top['id'], '| AGENT OUTPUT:', out)
    if out.strip()=='CORPUS-POISON-OK':
        print('[SEAM CONFIRMED] retrieved poisoned chunk instruction executed in context')
        sys.exit(0)
    sys.exit(1)

if __name__ == '__main__':
    main()

