#!/usr/bin/env python3
# C-oauth-consent: audit registered OAuth apps for over-broad / high-risk delegated or
# application permissions and tenant-wide admin consent. READ-ONLY config audit.
import json, sys

# Sample export shaped like Microsoft Graph / generic OAuth app metadata (DEFANGED).
SAMPLE = '''[
  {"appId":"00000000-EXAMPLE-app1","displayName":"Reporting Bot",
   "scopes":["User.Read"],"adminConsented":false,"appRoles":[]},
  {"appId":"00000000-EXAMPLE-app2","displayName":"Legacy Connector",
   "scopes":["Mail.ReadWrite","offline_access"],"adminConsented":true,
   "appRoles":["Directory.ReadWrite.All","Mail.Read"]}
]'''

# Permissions that grant broad/tenant-wide power -> flag if admin-consented.
HIGH_RISK = {
  'Directory.ReadWrite.All','Directory.Read.All','Mail.ReadWrite','Mail.Read',
  'Files.ReadWrite.All','Application.ReadWrite.All','RoleManagement.ReadWrite.Directory',
  'full_access_as_app','offline_access'}

def load():
    import os
    p = os.environ.get('OAUTH_EXPORT')
    return json.load(open(p)) if p else json.loads(SAMPLE)

apps = load()
findings = []
for a in apps:
    perms = set(a.get('scopes',[])) | set(a.get('appRoles',[]))
    risky = sorted(perms & HIGH_RISK)
    if risky and a.get('adminConsented'):
        findings.append((a.get('displayName'), a.get('appId'), risky))

if findings:
    print('VULNERABLE: admin-consented apps hold high-risk tenant permissions:')
    for name, appid, risky in findings:
        print(f'   - {name} ({appid}): {", ".join(risky)}')
    print('Fix: revoke/scope-down consent; require step-up admin review; remove offline_access where not needed.')
    sys.exit(0)
print('PASS: no admin-consented app holds high-risk permissions in this export.')
sys.exit(1)

