#!/usr/bin/env python3
# C-depconfusion: detect internal package names that are NOT scoped/pinned to a private
# registry, so a public package of the same name could be resolved instead. READ-ONLY.
# Does NOT query or publish to any registry.
import os, json, re, sys

# Names the org publishes/uses internally (DEFANGED examples).
INTERNAL = set((os.environ.get('INTERNAL_NAMES') or 'acme-auth acme-billing internal-utils').split())

SAMPLE_PKG = '''{
  "name": "acme-app",
  "dependencies": {
     "@acme/ui": "1.2.0",
     "acme-auth": "^2.0.0",
     "internal-utils": "latest",
     "lodash": "4.17.21"
  }
}'''

def deps():
    p = os.environ.get('MANIFEST')
    if p and p.endswith('.json'):
        return json.load(open(p)).get('dependencies',{})
    if p:  # requirements.txt style
        out={}
        for line in open(p):
            line=line.strip()
            if line and not line.startswith('#'):
                m=re.split(r'[=<>~!]',line,1); out[m[0]]= line
        return out
    return json.loads(SAMPLE_PKG)['dependencies']

d = deps()
findings=[]
for name, spec in d.items():
    is_scoped = name.startswith('@')                 # npm scope binds to a registry
    looks_internal = (name in INTERNAL) or (not is_scoped and name.startswith('acme'))
    loose = str(spec).lower() in ('latest','*','') or str(spec).startswith('^') or str(spec).startswith('~')
    if looks_internal and not is_scoped:
        findings.append((name, spec, 'internal name is UNSCOPED -> public registry can shadow it'))
    elif looks_internal and loose:
        findings.append((name, spec, 'internal name uses loose/floating version -> higher public-shadow risk'))

if findings:
    print('VULNERABLE: dependency-confusion exposure:')
    for n,s,why in findings: print(f'   - {n} ({s}): {why}')
    print('Fix: scope internal pkgs (@acme/...), pin exact versions, set registry scope + no public fallback.')
    sys.exit(0)
print('PASS: internal deps are scoped/pinned; no public-shadow exposure detected.')
sys.exit(1)

