#!/usr/bin/env python3
# CO-cluster-secrets-exposure: detect secret-looking values stored in plaintext env vars
# or ConfigMaps (base64 is NOT encryption). READ-ONLY; reports location, never prints the value.
import sys, json, re, base64

SAMPLE = {"items":[
  {"kind":"ConfigMap","metadata":{"name":"app-config","namespace":"prod"},
   "data":{"LOG_LEVEL":"info","DB_PASSWORD":"FAKE-PASSWORD-123","api_token":"FAKE-TOKEN"}},
  {"kind":"Pod","metadata":{"name":"api","namespace":"prod"},
   "spec":{"containers":[{"name":"c","env":[{"name":"AWS_SECRET_ACCESS_KEY","value":"FAKE-SECRET"},{"name":"PORT","value":"8080"}]}]}}
]}

SECRET_KEY = re.compile(r'(pass|pwd|secret|token|api[_-]?key|private[_-]?key|cred)', re.I)

def load():
    if not sys.stdin.isatty():
        raw = sys.stdin.read().strip()
        if raw:
            try: return json.loads(raw)
            except json.JSONDecodeError: pass
    if len(sys.argv) > 1:
        try: return json.load(open(sys.argv[1]))
        except (OSError, json.JSONDecodeError): pass
    return SAMPLE

d = load()
items = d.get('items', [d]) if isinstance(d, dict) else [d]
vuln = False
print('=== cluster secret-exposure scan ===')
for it in items:
    kind = it.get('kind','?'); md = it.get('metadata', {}) or {}
    name = md.get('name','?'); ns = md.get('namespace','?')
    # ConfigMap plaintext secret keys
    for k in (it.get('data', {}) or {}):
        if SECRET_KEY.search(k):
            vuln = True
