    # env literal values (not valueFrom secretKeyRef)
    for c in (it.get('spec', {}) or {}).get('containers', []) or []:
        for e in c.get('env', []) or []:
            if SECRET_KEY.search(e.get('name','')) and 'value' in e and 'valueFrom' not in e:
                vuln = True
                print(f'  {kind} {ns}/{name}: env "{e["name"]}" set as an inline literal value (should be valueFrom.secretKeyRef + encryption-at-rest).')
if vuln:
    print('VULNERABLE: secret-shaped values stored in ConfigMaps/inline env -> readable by anyone with get on the object. Move to Secrets w/ KMS encryption-at-rest, mount via secretKeyRef, restrict RBAC.')
else:
