#!/usr/bin/env python3
# AUTHORIZED LAB ONLY -- signed RoE. Symlink race inside a local temp sandbox only.
# C-toctou: check-then-use race; path validated then swapped to a symlink before open.
import os, tempfile

def safe_realpath(p):
    try:
        return os.path.realpath(p)
    except OSError:
        return None

def main():
    d = tempfile.mkdtemp(prefix="toctou_lab_")
    allowed = os.path.join(d, "allowed.txt")
    secret = os.path.join(d, "secret.txt")  # stands in for a privileged file
    open(allowed, "w").write("benign")
    open(secret, "w").write("FAKE-SECRET-CONTENT")
    target = os.path.join(d, "userpath")
    os.symlink(allowed, target)  # initially points at allowed file (passes check)

    # Deterministic window: the vulnerable code separates CHECK from USE.
    # We model the attacker swap that lands inside that window.
    def attacker_swap():
        os.remove(target); os.symlink(secret, target)

    leaked = None
    # CHECK: validate that the path resolves to the allowed file
    if safe_realpath(target) == safe_realpath(allowed):
        # ---- TOCTOU window: attacker repoints the symlink here ----
        attacker_swap()
        # USE: vulnerable code re-opens by path (no O_NOFOLLOW / fd reuse)
        data = open(target).read()
        if "FAKE-SECRET" in data:
            leaked = data
    if leaked:
        print("VULNERABLE: TOCTOU symlink swap leaked privileged file content after a passing check")
    else:
        print("PASS: use bound to checked inode (open with O_NOFOLLOW/openat would fix this)")

if __name__ == "__main__":
    main()

