# AUTHORIZED LAB ONLY -- signed RoE. JWT-style claim verification logic sim, no network.
# XC-cross-tenant-federation: verifier trusts issuer signature but does not pin tenant (tid)/audience.
import hmac, hashlib, base64, json

KEY = b"FAKE-FEDERATION-SIGNING-KEY"  # stands in for the shared/asymmetric trust anchor

def mint(claims):
    body = base64.urlsafe_b64encode(json.dumps(claims).encode()).decode()
    sig = hmac.new(KEY, body.encode(), hashlib.sha256).hexdigest()
    return body + "." + sig

def verify(token, expected_tid=None, expected_aud=None):
    body, sig = token.split(".")
    if not hmac.compare_digest(sig, hmac.new(KEY, body.encode(), hashlib.sha256).hexdigest()):
        return None
    claims = json.loads(base64.urlsafe_b64decode(body))
    if expected_tid is not None and claims.get("tid") != expected_tid:
        return None
    if expected_aud is not None and claims.get("aud") != expected_aud:
        return None
    return claims

