    foreign = mint({"sub": "attacker@other.example.test", "tid": "tenant-EVIL", "aud": "api://victim"})
    # VULNERABLE: app verifies signature only, no tid/aud pinning
    accepted = verify(foreign, expected_tid=None, expected_aud=None)
    # control: with pinning the foreign tenant is rejected
    rejected = verify(foreign, expected_tid="tenant-VICTIM", expected_aud="api://victim")
    if accepted and rejected is None:
        print("VULNERABLE: cross-tenant token accepted; issuer trusted without tenant/audience pinning")
