    forged = None
    for i in range(1 << 26):
        cand = b"transfer:amount=1000000;to=attacker@example.test;n=%d" % i
        if weak_tag(cand) == target_tag:
            forged = cand
            break
    if forged and forged != benign and verify(forged, target_tag):
        print(f"VULNERABLE: weak (24-bit) signature collides; forged message accepted under benign tag {target_tag}")
        print(f"  benign : {benign.decode()}")
        print(f"  forged : {forged.decode()}")
    else:
        print("PASS: no collision found within bound (use a full-width, collision-resistant MAC)")

if __name__ == "__main__":
    main()

