#!/usr/bin/env python3
# AUTHORIZED LAB ONLY -- signed RoE. Pure-logic PKI trust demo, no network.
# XC-ca-misissuance-trust: verifier accepts ANY chain to a trusted root, ignoring issuance control.
TRUSTED_ROOTS = {"FAKE-ROOT-CA"}

def chains_to_trusted(cert):
    return cert["issuer"] in TRUSTED_ROOTS

def verify_unsafe(cert, expected_host):
    # VULNERABLE: trust = "chains to a root we trust" + name match. No pinning / CAA / CT check.
    return chains_to_trusted(cert) and cert["subject"] == expected_host

def verify_safe(cert, expected_host, allowed_issuers_for_host):
    if not verify_unsafe(cert, expected_host):
        return False
    # issuance control: this host is only ever issued by a specific authorized CA (CAA/pinning/CT)
    return cert["issuer"] in allowed_issuers_for_host

def main():
    # A DIFFERENT, also-trusted CA mis-issues a cert for our host (no authorization to do so).
    rogue = {"subject": "login.example.test", "issuer": "FAKE-ROOT-CA"}
    host = "login.example.test"
    accepted = verify_unsafe(rogue, host)
    rejected = verify_safe(rogue, host, allowed_issuers_for_host={"FAKE-AUTHORIZED-CA-ONLY"})
    if accepted and not rejected:
        print("VULNERABLE: mis-issued cert accepted purely because it chains to a trusted root "
              "(no pinning/CAA/CT issuance control)")
    else:
        print("PASS: issuance control rejected the unauthorized issuer")

if __name__ == "__main__":
    main()

