#!/usr/bin/env python3
# AUTHORIZED LAB ONLY -- signed RoE. Lab crypto on local synthetic data only, no network.
# XC-padding-oracle-nonce-reuse: (A) IV/nonce reuse in a stream cipher leaks plaintext XOR;
#                                (B) a CBC padding oracle recovers a plaintext byte.
import hashlib, os

# --- A toy block cipher (lab only; NOT for real use): keyed SHA-256 permutation of an 8-byte block.
BS = 8
def block_encrypt(key, block):
    return bytes(b ^ k for b, k in zip(block, hashlib.sha256(key + b"E").digest()[:BS]))
def block_decrypt(key, block):
    return bytes(b ^ k for b, k in zip(block, hashlib.sha256(key + b"E").digest()[:BS]))

def xor(a, b): return bytes(x ^ y for x, y in zip(a, b))

# --- Stream-cipher keystream derived from (key, nonce). Reusing nonce reuses keystream.
def keystream(key, nonce, n):
    out = b""; ctr = 0
    while len(out) < n:
        out += hashlib.sha256(key + nonce + ctr.to_bytes(4, "big")).digest()
        ctr += 1
    return out[:n]

def stream_encrypt(key, nonce, pt):
    return xor(pt, keystream(key, nonce, len(pt)))

def part_a_nonce_reuse():
    key = os.urandom(16)
    nonce = b"FAKE-NONCE"  # VULNERABLE: same nonce used for two messages
    p1 = b"SECRET: balance=4242"
    p2 = b"PUBLIC: hello world!"  # attacker-known plaintext, same length
    c1 = stream_encrypt(key, nonce, p1)
    c2 = stream_encrypt(key, nonce, p2)
    # Attacker knows p2; recovers p1 with no key: p1 = c1 ^ c2 ^ p2
    recovered = xor(xor(c1, c2), p2)
    return recovered == p1, recovered

# --- CBC padding oracle: oracle leaks whether PKCS#7 padding is valid on decrypt.
def pkcs7_pad(b):
    p = BS - (len(b) % BS); return b + bytes([p]) * p
def pkcs7_unpad(b):
    p = b[-1]
    if p < 1 or p > BS or b[-p:] != bytes([p]) * p:
        raise ValueError("bad padding")
    return b[:-p]

def cbc_encrypt(key, iv, pt):
    pt = pkcs7_pad(pt); prev = iv; out = b""
    for i in range(0, len(pt), BS):
        out += (prev := block_encrypt(key, xor(pt[i:i+BS], prev)))
    return out
def cbc_decrypt_and_check(key, iv, ct):
    prev = iv; out = b""
    for i in range(0, len(ct), BS):
        blk = ct[i:i+BS]
        out += xor(block_decrypt(key, blk), prev); prev = blk
    pkcs7_unpad(out)  # raises on bad padding -> the ORACLE signal
    return True

def padding_oracle(key, iv, ct):
    # VULNERABLE: distinguishable response for padding validity
    try:
        cbc_decrypt_and_check(key, iv, ct); return True
    except ValueError:
        return False

def part_b_padding_oracle():
    key = os.urandom(16); iv = os.urandom(BS)
    secret = b"TOPSECRET"  # 9 bytes -> 2 blocks after pad
    ct = cbc_encrypt(key, iv, secret)
    blocks = [iv] + [ct[i:i+BS] for i in range(0, len(ct), BS)]
    # Recover the last byte of the last plaintext block using the oracle.
    c_prev, c_target = blocks[-2], blocks[-1]
    last_pt_byte = None
    for g in range(256):
        forged_prev = bytearray(c_prev)
        forged_prev[-1] = g  # try every value for the controlled previous-block byte
        if not padding_oracle(key, iv, bytes(forged_prev) + c_target):
            continue
        # Disambiguate: flip the second-to-last byte. If padding stays valid, it was
        # a length-1 pad (0x01); if it breaks, we matched a longer accidental pad -> skip.
        confirm = bytearray(forged_prev); confirm[-2] ^= 0xFF
        if not padding_oracle(key, iv, bytes(confirm) + c_target):
            continue
        intermediate = g ^ 0x01          # decrypted last byte forced to 0x01
        last_pt_byte = intermediate ^ c_prev[-1]  # real plaintext = intermediate ^ real C_prev byte
        break
    padded = pkcs7_pad(secret)
    true_last_byte = padded[-1]
    return last_pt_byte == true_last_byte, last_pt_byte, true_last_byte

def main():
    ok_a, rec = part_a_nonce_reuse()
    ok_b, got, exp = part_b_padding_oracle()
    if ok_a and ok_b:
        print("VULNERABLE: (A) nonce/IV reuse leaked plaintext via XOR; "
              f"recovered {rec!r}. (B) padding oracle recovered byte 0x{got:02x} (expected 0x{exp:02x}).")
    elif ok_a:
        print(f"VULNERABLE: nonce/IV reuse leaked plaintext via XOR -> {rec!r} (padding-oracle part inconclusive)")
    else:
        print("PASS: no plaintext recovered")

if __name__ == "__main__":
    main()

