#!/usr/bin/env python3
# AUTHORIZED LAB ONLY -- signed RoE. Handshake-logic simulation, no real TLS/network.
# XC-tls-downgrade-rollback: server accepts a MITM-stripped ClientHello forcing a weak cipher.
SERVER_SUPPORTED = ["TLS_AES_256_GCM", "TLS_CHACHA20_POLY1305", "TLS_RSA_RC4_128"]  # legacy still enabled
SECURE = {"TLS_AES_256_GCM", "TLS_CHACHA20_POLY1305"}

def negotiate(client_offer, enforce_min_strength=False, downgrade_protected=False):
    # MITM stripped strong suites, leaving only the weak one.
    common = [c for c in client_offer if c in SERVER_SUPPORTED]
    if not common:
        return None
    chosen = common[0]  # server picks client's top remaining preference
    if downgrade_protected:
        # downgrade sentinel (e.g., TLS1.3 random canary) would reveal the tampering
        return "ABORT-DOWNGRADE-DETECTED"
    if enforce_min_strength and chosen not in SECURE:
        return "ABORT-WEAK-CIPHER"
    return chosen

def main():
    real_client_offer = ["TLS_AES_256_GCM", "TLS_CHACHA20_POLY1305", "TLS_RSA_RC4_128"]
    mitm_stripped = ["TLS_RSA_RC4_128"]  # attacker removed the strong suites in flight
    # VULNERABLE: no min-strength floor, no downgrade-protection sentinel
    chosen = negotiate(mitm_stripped, enforce_min_strength=False, downgrade_protected=False)
    # control: hardened server rejects the same stripped hello
    ctrl = negotiate(mitm_stripped, enforce_min_strength=True, downgrade_protected=True)
    if chosen == "TLS_RSA_RC4_128" and ctrl != "TLS_RSA_RC4_128":
        print(f"VULNERABLE: downgrade/rollback accepted weak cipher {chosen} "
              "(no strength floor / no downgrade sentinel)")
    else:
        print("PASS: downgrade rejected; weak cipher not negotiated")

if __name__ == "__main__":
    main()
